    private Thread trackThread;

    public void playRadio() throws IOException, UnsupportedAudioFileException {
        AudioInputStream in = AudioSystem.getAudioInputStream(new URL(mp3Url));
        trackList = new HashMap<>();

        // Start a new thread to read the MP3 tags asynchronously
        trackThread = new Thread(() -> {
            try {
                MP3File mp3File = new MP3File(in);
                for (AbstractMP3Tag tag : mp3File.getTags()) {
                    String artist = tag.getArtist();
                    String title = tag.getTitle();
                    String track = artist + " - " + title;
                    trackList.put(tag.getTrackNumber(), track);
                }
            } catch (IOException | NotSupportedException | InvalidDataException e) {
                e.printStackTrace();
            }
        });

        trackThread.start();

        // Playback code here
    }

    public HashMap<Integer, String> getTrackList() {
        return trackList;
    }

