        RadioTracks radio = new RadioTracks();
        radio.mp3Url = "http://radio.com/mp3";
        radio.playRadio();
        HashMap<Integer, String> trackList = radio.getTrackList();
        for (int num : trackList.keySet()) {
            System.out.println(num + ": " + trackList.get(num));
        }
    }
}
