        trackList = new HashMap<>();

        // Start a new thread to read the MP3 tags asynchronously
        trackThread = new Thread(() -> {
            try {
                Mp3File mp3 = new Mp3File(in);
                if (mp3.hasId3v2Tag()) {
                    ID3v2 id3v2Tag = mp3.getId3v2Tag();
                    for (int i = 0; i < mp3.getFrameCount(); i++) {
                        if (mp3.getFrameAtIndex(i) instanceof ID3v2Frame) {
