                            if (frame.getId().matches("(TIT2|TPE1)")) {
                                String frameValue = new String(frame.getData(), "UTF-8");
                                String track = id3v2Tag.getArtist() + " - " + id3v2Tag.getTitle();
                                trackList.put(id3v2Tag.getTrack(), track);
                                break;
                            }
                        }
                    }
                }
            } catch (IOException | NotSupportedException | IllegalArgumentException | InvalidDataException e) {
                e.printStackTrace();
            }
        });

        trackThread.start();
        // Playback code here
    }

    public HashMap<Integer, String> getTrackList() {
